// uploads/BDR Design System v4 (1)/assets/catalog.js
try { (() => {
/* Catalog interactions + floating theme dock */
(function () {
  const T = window.BDRTheme;

  // floating dock
  const dock = document.getElementById('dock');
  function paintDock() {
    const s = T.state,
      m = T.effMode(),
      acc = T.curAccent();
    dock.querySelector('[data-dock-mode]').innerHTML = m === 'dark' ? '<span class="material-symbols-outlined">dark_mode</span>' : '<span class="material-symbols-outlined">light_mode</span>';
    dock.querySelectorAll('[data-acc]').forEach(b => b.classList.toggle('on', b.dataset.acc === acc));
    document.getElementById('dockMode').textContent = s.mode === 'system' ? '시스템(' + m + ')' : m === 'dark' ? '다크' : '라이트';
    document.getElementById('dockAcc').textContent = T.ACCENTS[acc].name;
  }
  dock.querySelector('[data-dock-mode]').onclick = () => T.toggleMode();
  dock.querySelectorAll('[data-acc]').forEach(b => b.onclick = () => T.setAccent(b.dataset.acc));
  T.onChange(paintDock);
  paintDock();

  // section nav scrollspy
  const links = [...document.querySelectorAll('.toc a')];
  const secs = links.map(a => document.querySelector(a.getAttribute('href')));
  function spy() {
    let idx = 0;
    secs.forEach((s, i) => {
      if (s && s.getBoundingClientRect().top < 140) idx = i;
    });
    links.forEach((a, i) => a.classList.toggle('on', i === idx));
  }
  window.addEventListener('scroll', spy, {
    passive: true
  });
  spy();
  links.forEach(a => a.onclick = e => {
    e.preventDefault();
    const t = document.querySelector(a.getAttribute('href'));
    window.scrollTo({
      top: t.offsetTop - 90,
      behavior: 'smooth'
    });
  });

  // demo toggles / segmented / tabs / checks
  document.querySelectorAll('.demo .tg').forEach(tg => tg.onclick = () => tg.setAttribute('aria-pressed', tg.getAttribute('aria-pressed') !== 'true'));
  document.querySelectorAll('.demo .seg').forEach(seg => seg.querySelectorAll('button').forEach(b => b.onclick = () => seg.querySelectorAll('button').forEach(x => x.setAttribute('aria-pressed', x === b))));
  document.querySelectorAll('.demo .tabs').forEach(tb => tb.querySelectorAll('button').forEach(b => b.onclick = () => tb.querySelectorAll('button').forEach(x => x.setAttribute('aria-selected', x === b))));

  // toast
  let tc = document.getElementById('toastWrap');
  window.fireToast = function (kind) {
    const map = {
      ok: ['check_circle', '저장되었습니다', '경기 기록이 동기화됐어요.'],
      info: ['info', '대진표 업데이트', '8강 대진이 확정되었습니다.'],
      warn: ['warning', '마감 임박', '접수가 1시간 뒤 종료됩니다.'],
      err: ['error', '전송 실패', '네트워크를 확인해 주세요.']
    };
    const [ic, ti, ds] = map[kind];
    const el = document.createElement('div');
    el.className = 'toast toast--' + kind;
    el.innerHTML = '<span class="material-symbols-outlined ti">' + ic + '</span><div class="tx"><b>' + ti + '</b><span>' + ds + '</span></div><button class="tcl material-symbols-outlined">close</button>';
    el.querySelector('.tcl').onclick = () => el.remove();
    tc.appendChild(el);
    setTimeout(() => {
      el.style.opacity = '0';
      el.style.transform = 'translateX(20px)';
      setTimeout(() => el.remove(), 300);
    }, 3600);
  };

  // modal
  const modal = document.getElementById('modal');
  window.openModal = () => modal.classList.add('on');
  window.closeModal = () => modal.classList.remove('on');
  modal.addEventListener('click', e => {
    if (e.target === modal) closeModal();
  });

  // skeleton -> content swap demo
  window.reloadCard = function (btn) {
    const card = document.getElementById('loadCard');
    card.classList.add('loading');
    btn.disabled = true;
    setTimeout(() => {
      card.classList.remove('loading');
      btn.disabled = false;
    }, 1500);
  };

  // stepper
  const sv = document.getElementById('stepVal');
  if (sv) document.querySelectorAll('.stepper [data-step]').forEach(b => b.onclick = () => {
    sv.textContent = Math.max(0, parseInt(sv.textContent, 10) + parseInt(b.dataset.step, 10));
  });
  // range label
  const ri = document.getElementById('rangeIn'),
    rv = document.getElementById('rangeVal');
  if (ri) ri.oninput = () => {
    const v = +ri.value;
    rv.textContent = v < 33 ? '낮음' : v < 66 ? '중간' : '높음';
  };

  // accordion
  document.querySelectorAll('#accList .acc-hd').forEach(h => h.onclick = () => {
    h.closest('.acc-item').classList.toggle('open');
  });
  // calendar day select
  const cal = document.getElementById('cal');
  if (cal) cal.querySelectorAll('.cal__d:not(.mute)').forEach(d => d.onclick = () => {
    cal.querySelectorAll('.cal__d').forEach(x => x.classList.remove('sel'));
    d.classList.add('sel');
  });
  // remove tag chips / file items
  document.querySelectorAll('.tagchip button').forEach(b => b.onclick = () => b.closest('.tagchip').remove());
  document.querySelectorAll('.fileitem .iconbtn').forEach(b => b.onclick = () => b.closest('.fileitem').remove());
  // tag input add on Enter
  document.querySelectorAll('.taginput input').forEach(inp => inp.onkeydown = e => {
    if (e.key === 'Enter' && inp.value.trim()) {
      const chip = document.createElement('span');
      chip.className = 'tagchip';
      chip.innerHTML = inp.value.trim() + '<button><span class="material-symbols-outlined">close</span></button>';
      chip.querySelector('button').onclick = () => chip.remove();
      inp.parentNode.insertBefore(chip, inp);
      inp.value = '';
    }
  });
})();
})(); } catch (e) { __ds_ns.__errors.push({ path: "uploads/BDR Design System v4 (1)/assets/catalog.js", error: String((e && e.message) || e) }); }

